#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> nums;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        nums.push_back(x);
    }

    int sum { 0 };
    for (int x : nums)
        sum += x;

    std::cout << sum << '\n';
    return 0;
}

