solution_code:
#include <iostream>
#include <vector>

void doubleAll(std::vector<int>& v)
{
    for (int& x : v)
        x *= 2;
}

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> nums;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        nums.push_back(x);
    }

    doubleAll(nums);

    for (int i = 0; i < static_cast<int>(nums.size()); ++i)
    {
        if (i > 0) std::cout << ' ';
        std::cout << nums[i];
    }
    std::cout << '\n';
    return 0;
}
